# Fraud detection: feature velocity + focal loss
import tensorflow as tf

# Focal loss for extreme class imbalance (fraud ~ 0.1%)
def focal_loss(gamma=2.0, alpha=0.25):
    def loss(y_true, y_pred):
        pt = tf.where(tf.equal(y_true, 1), y_pred, 1 - y_pred)
        return -tf.reduce_mean(
            alpha * tf.pow(1 - pt, gamma) * tf.math.log(pt + 1e-6))
    return loss

# Feature engineering: transaction velocity
# (precomputed in Flink streaming, joined at inference time)
features = {
    'amount': float,
    'transaction_velocity_1h': int,    # Count of txns in last hour
    'transaction_velocity_24h': int,
    'amount_velocity_24h': float,       # Total $ amount in 24h
    'location_distance_km': float,      # IP vs shipping address
    'device_age_days': int,
    'user_agent_entropy': float,        # Unusual browser patterns
    'is_new_device': bool,
    'num_failed_attempts_1h': int,
}

# Human-in-the-loop policy
def routing_decision(fraud_prob):
    if fraud_prob > 0.9:
        return "BLOCK + manual review"
    elif fraud_prob > 0.5:
        return "CHALLENGE (2FA)"
    else:
        return "APPROVE"
